const payload = $json.body ?? $json ?? {};
const timezone = 'America/Chicago';
const explicitDate = typeof payload.target_date === 'string' ? payload.target_date.trim() : '';
function formatChicagoDate(date) {
  return new Intl.DateTimeFormat('en-CA', { timeZone: timezone, year: 'numeric', month: '2-digit', day: '2-digit' }).format(date);
}
let targetDate = explicitDate;
if (!targetDate) {
  const now = new Date();
  const nowInChicago = new Date(now.toLocaleString('en-US', { timeZone: timezone }));
  nowInChicago.setDate(nowInChicago.getDate() - 1);
  targetDate = formatChicagoDate(nowInChicago);
}
return [{ json: { target_date: targetDate, unique_key: 'fathom_daily_summary_' + targetDate, run_reason: explicitDate ? 'manual_target_date' : 'scheduled_yesterday', requested_payload: payload } }];

