const prompt = $('Build Daily Summary Prompt').first().json;
let raw = $json.output;
let parsed;
if (raw && typeof raw === 'object') {
  parsed = raw;
} else {
  raw = String(raw || '').trim();
  const fence = String.fromCharCode(96, 96, 96);
  if (raw.startsWith(fence + 'json')) raw = raw.slice((fence + 'json').length).trim();
  if (raw.startsWith(fence)) raw = raw.slice(fence.length).trim();
  if (raw.endsWith(fence)) raw = raw.slice(0, -fence.length).trim();
  raw = raw.split('\n').join(' ');
  raw = raw.split('\r').join(' ');
  raw = raw.split('\t').join(' ');
  parsed = JSON.parse(raw);
}
const title = parsed.title || ('Daily Journal - Fathom - ' + prompt.target_date);
const summary = parsed.summary || 'Daily Fathom summary generated from journal entries.';
const details = parsed.details || {};
return [{ json: { source_id: null, journal_date: prompt.target_date, occurred_at: new Date(prompt.target_date + 'T23:59:00Z').toISOString(), entry_type: 'daily_summary', importance: 'normal', actor_name: null, project_id: null, project_name: null, team_name: 'Solution Architects', title, summary, details: { source_type: 'fathom_daily_summary', target_date: prompt.target_date, meeting_count: prompt.meeting_count, themes: Array.isArray(details.themes) ? details.themes : [], key_updates: Array.isArray(details.key_updates) ? details.key_updates : [], risks: Array.isArray(details.risks) ? details.risks : [], follow_ups: Array.isArray(details.follow_ups) ? details.follow_ups : [], meetings: prompt.meetings, raw_model_output: parsed }, links: { unique_key: prompt.unique_key, source_type: 'fathom_daily_summary' } } }];

